// ══════════════════════════════════════════════
// STEP 1: Message থেকে সব দরকারি তথ্য বের করো
// ══════════════════════════════════════════════

const body = $input.first().json.body || $input.first().json;

const msgId          = body.msgId || '';
const jid            = body.jid || '';
const isGroup        = body.isGroup || false;
const senderNumber   = body.senderNumber || '';
const senderName     = body.senderName || 'User';
const messageContent = body.messageContent || '';
const myName         = body.myName || '';
const myPhone        = body.myPhone || '';
const timestamp      = body.timestamp || Date.now();

// ── Sleep Mode Check ──────────────────────────────────────────
// রাত 11টা থেকে সকাল 7টা পর্যন্ত reply বন্ধ
const hour = new Date().getHours();
const SLEEP_START = 23;
const SLEEP_END   = 7;
const isSleepTime = hour >= SLEEP_START || hour < SLEEP_END;

// ── Blacklist Check ───────────────────────────────────────────
// এই নম্বরগুলোকে কখনো reply দেওয়া হবে না
const BLACKLIST = [];
// উদাহরণ: const BLACKLIST = ['8801XXXXXXXXX', '8801YYYYYYYYY'];
const isBlacklisted = BLACKLIST.includes(senderNumber);

// ── Spam Check ────────────────────────────────────────────────
const SPAM_KEYWORDS = ['win prize', 'click here', 'free money', 'lottery', 'http://', 'https://bit.ly'];
const messageLC = messageContent.toLowerCase();
const isSpam = SPAM_KEYWORDS.some(kw => messageLC.includes(kw));

// ── Group Mention Check ───────────────────────────────────────
// Group এ reply শুধু যদি আমার নাম mention করা হয়
const myNameMentioned = myName ? messageLC.includes(myName.toLowerCase()) : false;

// ── Should Reply? ─────────────────────────────────────────────
let shouldReply = false;
let skipReason  = '';

if (isSleepTime) {
  shouldReply = false;
  skipReason  = 'sleep_mode';
} else if (isBlacklisted) {
  shouldReply = false;
  skipReason  = 'blacklisted';
} else if (isSpam) {
  shouldReply = false;
  skipReason  = 'spam';
} else if (senderNumber === myPhone) {
  shouldReply = false;
  skipReason  = 'own_message';
} else if (isGroup && !myNameMentioned) {
  shouldReply = false;
  skipReason  = 'group_not_mentioned';
} else {
  shouldReply = true;
}

// ── Personality Prompt ────────────────────────────────────────
// চাইলে এখানে তোমার নিজের personality যোগ করো
const SYSTEM_PROMPTS = {
  friendly:     'তুমি একজন বন্ধুত্বপূর্ণ মানুষ। সংক্ষিপ্ত এবং স্বাভাবিকভাবে reply করো। বাংলা বা ইংরেজিতে যে ভাষায় message এসেছে সেই ভাষায় reply করো।',
  professional: 'Reply professionally and concisely. Keep it short and to the point.',
  funny:        'Reply in a funny, witty way. Use humor naturally but keep it short.',
  casual:       'Reply casually like a friend. Use informal language. Keep it brief.',
};

const PERSONALITY = 'friendly'; // .env থেকে নেওয়া যায়
const systemPrompt = SYSTEM_PROMPTS[PERSONALITY] || SYSTEM_PROMPTS.friendly;

console.log(`[n8n] Message from: ${senderName} | Group: ${isGroup} | Reply: ${shouldReply} | Reason: ${skipReason}`);

return [{
  json: {
    msgId,
    jid,
    isGroup,
    senderNumber,
    senderName,
    messageContent,
    myName,
    shouldReply,
    skipReason,
    systemPrompt,
    timestamp,
  }
}];

// ══════════════════════════════════════════════
// STEP 2: Groq API response থেকে reply text বের করো
// ══════════════════════════════════════════════

const groqResponse = $input.first().json;
const prevData     = $('Function - Preprocess & Filter').first().json;

// Groq API response structure:
// { choices: [{ message: { content: '...' } }] }
let replyText = '';

try {
  replyText = groqResponse.choices[0].message.content.trim();
} catch (e) {
  replyText = 'একটু পরে reply করছি! 😊';
  console.error('Groq response parse error:', e);
}

// Typing delay calculate করো (message length অনুযায়ী)
// প্রতি character এর জন্য ~50ms — human-like typing simulation
const typingDelayMs = Math.min(replyText.length * 50, 4000); // Max 4 seconds

console.log(`[n8n] AI Reply (${replyText.length} chars): ${replyText.substring(0, 60)}...`);
console.log(`[n8n] Typing delay: ${typingDelayMs}ms`);

return [{
  json: {
    jid:          prevData.jid,
    replyText,
    typingDelayMs,
    senderName:   prevData.senderName,
    isGroup:      prevData.isGroup,
  }
}];
